def call_agent(chunks,model_name,api_key,ollama_flag):
    SYSTEM_PROMPT = """
                        You are an expert software engineer specializing in code analysis.
                        Your task is to analyze a list of code chunks and generate a structured 
                        summary for EACH chunk. The summaries will be used for:
                        1. Building file level summaries
                        2. Building modular level summaries
                        3. Powering a RAG system where developers ask questions about the codebase

                        Input format is a list where each chunk has:
                        - code: the actual code
                        - tokens: token count
                        - filename: which file it belongs to

                        Rules:
                        - Generate one summary per chunk in the same order as input
                        - logic_summary must be detailed enough to understand WITHOUT reading the code
                        - complexity must be: utility | core_logic | critical_path
                        - tags should reflect what a developer would search for
                        - for non-class code set class_purpose, attributes, methods_overview, inheritance to null
                        When analyzing anonymous JavaScript or Python functions,
                        infer a meaningful contextual name based on its usage,
                        behavior, file, or surrounding logic.

                        Avoid generic placeholders like:
                        - anonymous
                        - unnamed_function

                        Examples:
                        - anonymous_auth_middleware
                        - anonymous_queue_worker
                        - anonymous_react_callback
                        - anonymous_jwt_generator
                        - anonymous_context_hook
                    """
    try:
        if ollama_flag == True:
            llm = load_model_ollama(model_name)
        else:
            llm = load_model_byok(model_name,api_key)
        structured_llm = llm.with_structured_output(ChunkSummaryList)
        messages = [
            (
                "system",
                SYSTEM_PROMPT,
            ),
            ("human", f"Analyze the given chunks and generate the answer according to the system prompt only {chunks}"),
        ]
        print(f"Successfully imported and structured the model = {model_name} for chunk analysis")
        ai_msg = structured_llm.invoke(messages)
        return ai_msg

    except Exception as e:
        print(f"Agent for source code analysis failed!! as  {e}")

def generate_chunks_summary(chunks_for_embedding,model_name,api_key,ollama_flag):
    # Takes the chunks_for_embedding as input and provides  summary as additional object in the numpy array chunks_for_embedding
    MAX_TOKEN_LIMIT = load_max_token(model_name,ollama_flag)
    without_token_size_chunks_for_embedding = [ {k: v for k, v in item.items() if k != "tokens"} for item in chunks_for_embedding ]
    current_request_chunks_size = 0
    give_chunks = []
    ai_msg = []
    try :
        for chunk,clean_chunk in zip(chunks_for_embedding,without_token_size_chunks_for_embedding):
            current_request_chunks_size += chunk["tokens"]
            if current_request_chunks_size >= MAX_TOKEN_LIMIT:
                result = call_agent(give_chunks,model_name,api_key,ollama_flag)
                ai_msg.extend(result.summaries)
                if ollama_flag == False:
                    print("Waiting 60 seconds....")
                    time.sleep(60)
                    print("Done waiting 60 seconds!!")
                else:
                    print("Waiting 10 seconds....")
                    time.sleep(10)
                    print("Done waiting 10 seconds!!")
                current_request_chunks_size = chunk["tokens"]
                give_chunks = []
            give_chunks.append(clean_chunk)

        if give_chunks:
            result = call_agent(give_chunks,model_name,api_key,ollama_flag)
            ai_msg.extend(result.summaries)
        return ai_msg
    except Exception as e:
        print(f"Something went wrong while initiating code analysis via LLM as {e}")


